import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversalExample {

    private static final String BASE_DIRECTORY = "C:/data/";

    public static void main(String[] args) {
        if (args.length != 1) {
            System.out.println("Usage: java SecurePathTraversalExample <filename>");
            return;
        }

        String fileName = args[0];
        String filePath = Paths.get(BASE_DIRECTORY, fileName).normalize().toString();

        if (!filePath.startsWith(BASE_DIRECTORY)) {
            System.out.println("Invalid file path.");
            return;
        }

        File file = new File(filePath);

        try (FileInputStream fis = new FileInputStream(file)) {
            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

